module RefModule(T, S, R, CLK, Q, QN);input T, S, R, CLK;
  output Q, QN;
  reg Q, QN;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (S) begin
      Q <= 1;
      QN <= 0;
    end else if (R) begin
      Q <= 0;
      QN <= 1;
    end else if (T) begin
      Q <= ~Q;
      QN <= ~QN;
    end
  end
endmodule
